        {"name": "导赤散", "source": "《小儿药证直诀》", "section": "卷下", "composition": "生地黄、木通、生甘草梢各等分", "effects": "清心利水养阴", "indications": "心经火热证。心胸烦热，口渴面赤，意欲冷饮，以及口舌生疮；或心热移于小肠，小便赤涩刺痛，舌红，脉数", "usage": "入竹叶，水煎服"},
        {"name": "龙胆泻肝汤", "source": "《医方集解》", "section": "卷下", "composition": "龙胆草（酒炒）二钱，黄芩（炒）二钱，栀子（酒炒）二钱，泽泻二钱，木通一钱，车前子一钱，当归（酒洗）一钱，生地黄（酒炒）二钱，柴胡二钱，生甘草一钱", "effects": "清泻肝胆实火，清利肝经湿热", "indications": "肝胆实火上炎证。头痛目赤，胁痛，口苦，耳聋，耳肿，舌红苔黄，脉弦细有力；或肝经湿热下注证", "usage": "水煎服"},
        {"name": "左金丸", "source": "《丹溪心法》", "section": "卷一", "composition": "黄连六两，吴茱萸一两或半两", "effects": "清泻肝火，降逆止呕", "indications": "肝火犯胃证。胁肋疼痛，嘈杂吞酸，呕吐口苦，舌红苔黄，脉弦数", "usage": "共为末，水丸或蒸饼为丸，白汤下五十丸"},
        {"name": "苇茎汤", "source": "《备急千金要方》", "section": "卷十七", "composition": "苇茎二升，薏苡仁半升，瓜瓣半升，桃仁三十枚", "effects": "清肺化痰，逐瘀排脓", "indications": "肺痈，热毒壅滞，痰瘀互结证。身有微热，咳嗽痰多，甚则咳吐腥臭脓血，胸中隐隐作痛，舌红苔黄腻，脉滑数", "usage": "水煎服"},
        {"name": "泻白散", "source": "《小儿药证直诀》", "section": "卷下", "composition": "地骨皮、桑白皮各一两，甘草一钱", "effects": "清泻肺热，止咳平喘", "indications": "肺热喘咳证。气喘咳嗽，皮肤蒸热，日晡尤甚，舌红苔黄，脉细数", "usage": "入粳米一撮，水煎服"},
        {"name": "清胃散", "source": "《脾胃论》", "section": "卷下", "composition": "生地黄、当归身各三分，牡丹皮半钱，黄连六分（夏月倍之，大抵黄连临时增减无定），升麻一钱", "effects": "清胃凉血", "indications": "胃火牙痛。牙痛牵引头疼，面颊发热，其齿喜冷恶热，或牙宣出血，或牙龈红肿溃烂，或唇舌腮颊肿痛，口气热臭，口干舌燥，舌红苔黄，脉滑数", "usage": "共为细末，都作一服，水一盏半，煎至七分，去滓，放冷服之"},
        {"name": "玉女煎", "source": "《景岳全书》", "section": "卷五十一", "composition": "石膏三至五钱，熟地三至五钱或一两，麦冬二钱，知母、牛膝各一钱半", "effects": "清胃热，滋肾阴", "indications": "胃热阴虚证。头痛，牙痛，齿松牙衄，烦热干渴，舌红苔黄而干。亦治消渴，消谷善饥等", "usage": "水一盅半，煎七分，温服或冷服"},
        {"name": "芍药汤", "source": "《素问病机气宜保命集》", "section": "卷中", "composition": "芍药一两，当归半两，黄连半两，槟榔、木香、甘草（炙）各二钱，大黄三钱，黄芩半两，官桂二钱半", "effects": "清热燥湿，调气和血", "indications": "湿热痢疾。腹痛，便脓血，赤白相兼，里急后重，肛门灼热，小便短赤，舌苔黄腻，脉弦数", "usage": "水煎服"},
        {"name": "白头翁汤", "source": "《伤寒论》", "section": "第371条", "composition": "白头翁二两，黄柏三两，黄连三两，秦皮三两", "effects": "清热解毒，凉血止痢", "indications": "热毒痢疾。腹痛，里急后重，肛门灼热，下痢脓血，赤多白少，渴欲饮水，舌红苔黄，脉弦数", "usage": "水煎服"},
        {"name": "青蒿鳖甲汤", "source": "《温病条辨》", "section": "卷三", "composition": "青蒿二钱，鳖甲五钱，细生地四钱，知母二钱，丹皮三钱", "effects": "养阴透热", "indications": "温病后期，邪伏阴分证。夜热早凉，热退无汗，舌红少苔，脉细数", "usage": "水五杯，煮取二杯，日再服"},
        {"name": "清骨散", "source": "《证治准绳》", "section": "卷一", "composition": "银柴胡一钱五分，胡黄连、秦艽、鳖甲（醋炙）、地骨皮、青蒿、知母各一钱，甘草五分", "effects": "清虚热，退骨蒸", "indications": "肝肾阴虚，虚火内扰证。骨蒸劳热，或低热日久不退，形体消瘦，唇红颧赤，困倦盗汗，或口渴心烦，舌红少苔，脉细数", "usage": "水二钟，煎八分，食远服"},
        {"name": "当归六黄汤", "source": "《兰室秘藏》", "section": "卷下", "composition": "当归、生地黄、熟地黄、黄芩、黄柏、黄连各等分，黄芪加一倍", "effects": "滋阴泻火，固表止汗", "indications": "阴虚火旺盗汗。发热盗汗，面赤心烦，口干唇燥，大便干结，小便黄赤，舌红苔黄，脉数", "usage": "共为粗末，每服五钱，水二盏，煎至一盏，食前服"},
        {"name": "五苓散", "source": "《伤寒论》", "section": "第71条", "composition": "猪苓十八铢（去皮），泽泻一两六铢，白术十八铢，茯苓十八铢，桂枝半两（去皮）", "effects": "利水渗湿，温阳化气", "indications": "蓄水证。小便不利，头痛微热，烦渴欲饮，甚则水入即吐，舌苔白，脉浮；或痰饮，脐下动悸，吐涎沫而头眩；或短气而咳；或水肿、泄泻", "usage": "共为散，以白饮和服方寸匕，日三服，多饮暖水，汗出愈"},
        {"name": "猪苓汤", "source": "《伤寒论》", "section": "第223条", "composition": "猪苓（去皮）、茯苓、泽泻、阿胶、滑石（碎）各一两", "effects": "利水渗湿，清热养阴", "indications": "水热互结证。小便不利，发热，口渴欲饮，或心烦不寐，或兼有咳嗽、呕恶、下利，舌红苔白或微黄，脉细数；或血淋，小便涩痛，点滴难出，小腹满痛者", "usage": "以水四升，先煮四味，取二升，去滓，内阿胶烊消，温服七合，日三服"},
        {"name": "防己黄芪汤", "source": "《金匮要略》", "section": "水气病脉证并治", "composition": "防己一两，甘草半两（炒），白术七钱半，黄芪一两一分（去芦）", "effects": "益气祛风，健脾利水", "indications": "表虚不固之风水或风湿证。汗出恶风，身重微肿，或肢节疼痛，小便不利，舌淡苔白，脉浮", "usage": "加生姜、大枣，水煎服"},
        {"name": "真武汤", "source": "《伤寒论》", "section": "第316条", "composition": "茯苓、芍药、生姜（切）各三两，白术二两，附子一枚（炮，去皮，破八片）", "effects": "温阳利水", "indications": "阳虚水泛证。畏寒肢厥，小便不利，心下悸动不宁，头目眩晕，身体筋肉瞤动，站立不稳，四肢沉重疼痛，浮肿，腰以下为甚；或腹痛，泄泻；或咳喘呕逆", "usage": "水煎服"},
        {"name": "实脾散", "source": "《重订严氏济生方》", "section": "水肿门", "composition": "厚朴（去皮，姜制，炒）、白术、木瓜（去瓤）、木香（不见火）、草果仁、大腹子、附子（炮，去皮脐）、白茯苓（去皮）、干姜（炮）各一两，甘草（炙）半两", "effects": "温阳健脾，行气利水", "indications": "脾肾阳虚，水气内停之阴水。身半以下肿甚，手足不温，口中不渴，胸腹胀满，大便溏薄，舌苔白腻，脉沉弦而迟", "usage": "加生姜、大枣，水煎服"},
        {"name": "完带汤", "source": "《傅青主女科》", "section": "卷上", "composition": "白术一两（土炒），山药一两（炒），人参二钱，白芍五钱（酒炒），车前子三钱（酒炒），苍术三钱（制），甘草一钱，陈皮五分，黑芥穗五分，柴胡六分", "effects": "补脾疏肝，化湿止带", "indications": "脾虚肝郁，湿浊带下。带下色白，清稀无臭，面色㿠白，倦怠便溏，舌淡苔白，脉缓或濡弱", "usage": "水煎服"},
        {"name": "二妙散", "source": "《丹溪心法》", "section": "卷四", "composition": "黄柏（炒）、苍术（米泔浸炒）各等分", "effects": "清热燥湿", "indications": "湿热下注证。筋骨疼痛，或两足痿软，或足膝红肿疼痛，或湿热带下，或下部湿疮、湿疹，小便短赤，舌苔黄腻", "usage": "共为末，沸汤入姜汁调服"},
        {"name": "八正散", "source": "《太平惠民和剂局方》", "section": "卷六", "composition": "车前子、瞿麦、萹蓄、滑石、山栀子仁、甘草（炙）、木通、大黄（面裹煨，去面，切，焙）各一斤", "effects": "清热泻火，利水通淋", "indications": "湿热淋证。尿频尿急，溺时涩痛，淋沥不畅，尿色浑赤，甚则癃闭不通，小腹急满，口燥咽干，舌苔黄腻，脉滑数", "usage": "共为散，每服二钱，水一盏，入灯心，煎至七分，食后温服"},
        {"name": "三仁汤", "source": "《温病条辨》", "section": "卷一", "composition": "杏仁五钱，飞滑石六钱，白通草二钱，白蔻仁二钱，竹叶二钱，厚朴二钱，生薏苡仁六钱，半夏五钱", "effects": "宣畅气机，清利湿热", "indications": "湿温初起及暑温夹湿之湿重于热证。头痛恶寒，身重疼痛，肢体倦怠，面色淡黄，胸闷不饥，午后身热，苔白不渴，脉弦细而濡", "usage": "甘澜水八碗，煮取三碗，每服一碗，日三服"},
        {"name": "甘露消毒丹", "source": "《医效秘传》", "section": "卷一", "composition": "飞滑石十五两，淡黄芩十两，绵茵陈十一两，石菖蒲六两，川贝母、木通各五两，藿香、连翘、白蔻仁、薄荷、射干各四两", "effects": "利湿化浊，清热解毒", "indications": "湿温时疫，邪在气分，湿热并重证。发热倦怠，胸闷腹胀，肢酸咽痛，身目发黄，颐肿口渴，小便短赤，泄泻淋浊，舌苔白或厚腻或干黄，脉濡数或滑数", "usage": "共为细末，每服三钱，开水调下，或神曲糊丸"},
        {"name": "连朴饮", "source": "《霍乱论》", "section": "卷下", "composition": "制厚朴二钱，川连（姜汁炒）、石菖蒲、制半夏各一钱，香豉（炒）、焦栀各三钱，芦根二两", "effects": "清热化湿，理气和中", "indications": "湿热霍乱。上吐下泻，胸脘痞闷，心烦躁扰，小便短赤，舌苔黄腻，脉滑数", "usage": "水煎服"},
        {"name": "当归拈痛汤", "source": "《医学启源》", "section": "卷中", "composition": "羌活半两，防风三钱，升麻一钱，葛根二钱，白术一钱，苍术三钱，当归身三钱，人参二钱，甘草五钱，苦参（酒浸）二钱，黄芩一钱（炒），知母三钱（酒洗），茵陈五钱（酒炒），猪苓三钱，泽泻三钱", "effects": "利湿清热，疏风止痛", "indications": "湿热相搏，外受风邪证。遍身肢节烦痛，或肩背沉重，或脚气肿痛，脚膝生疮，舌苔白腻微黄，脉弦数", "usage": "水煎服"},
        {"name": "二陈汤", "source": "《太平惠民和剂局方》", "section": "卷四", "composition": "半夏（汤洗七次）、橘红各五两，白茯苓三两，甘草（炙）一两半", "effects": "燥湿化痰，理气和中", "indications": "湿痰证。咳嗽痰多，色白易咯，恶心呕吐，胸膈痞闷，肢体困重，或头眩心悸，舌苔白滑或腻，脉滑", "usage": "加生姜七片，乌梅一个，水煎服"},
        {"name": "温胆汤", "source": "《三因极一病证方论》", "section": "卷九", "composition": "半夏（汤洗七次）、竹茹、枳实（麸炒，去瓤）各二两，陈皮三两，甘草（炙）一两，茯苓一两半", "effects": "理气化痰，和胃利胆", "indications": "胆郁痰扰证。胆怯易惊，头眩心悸，心烦不眠，夜多异梦；或呕恶呃逆，眩晕，癫痫。苔白腻，脉弦滑", "usage": "加生姜五片，大枣一枚，水煎服"},
        {"name": "清气化痰丸", "source": "《医方考》", "section": "卷二", "composition": "陈皮（去白）、杏仁（去皮尖）、枳实（麸炒）、黄芩（酒炒）、瓜蒌仁（去油）、茯苓各一两，胆南星、制半夏各一两半", "effects": "清热化痰，理气止咳", "indications": "痰热咳嗽。咳嗽气喘，咳痰黄稠，胸膈痞闷，甚则气急呕恶，烦躁不宁，舌质红，苔黄腻，脉滑数", "usage": "姜汁为丸，每服二至三钱，温开水下"},
        {"name": "贝母瓜蒌散", "source": "《医学心悟》", "section": "卷三", "composition": "贝母一钱五分，瓜蒌一钱，花粉、茯苓、橘红、桔梗各八分", "effects": "润肺清热，理气化痰", "indications": "燥痰咳嗽。咳嗽呛急，咯痰不爽，涩而难出，咽喉干燥哽痛，苔白而干", "usage": "水煎服"},
        {"name": "苓甘五味姜辛汤", "source": "《金匮要略》", "section": "痰饮咳嗽病脉证并治", "composition": "茯苓四两，甘草三两，干姜三两，细辛三两，五味子半升", "effects": "温肺化饮", "indications": "寒饮咳嗽。咳痰量多，清稀色白，或喜唾涎沫，胸满不舒，舌苔白滑，脉弦滑", "usage": "水煎服"},
        {"name": "半夏白术天麻汤", "source": "《医学心悟》", "section": "卷三", "composition": "半夏一钱五分，天麻、茯苓、橘红各一钱，白术三钱，甘草五分", "effects": "化痰熄风，健脾祛湿", "indications": "风痰上扰证。眩晕，头痛，胸膈痞闷，恶心呕吐，舌苔白腻，脉弦滑", "usage": "加生姜一片，大枣二枚，水煎服"},
        {"name": "保和丸", "source": "《丹溪心法》", "section": "卷三", "composition": "山楂六两，神曲二两，半夏、茯苓各三两，陈皮、连翘、莱菔子各一两", "effects": "消食和胃", "indications": "食积证。脘腹痞满胀痛，嗳腐吞酸，恶食呕逆，或大便泄泻，舌苔厚腻，脉滑", "usage": "共为末，炊饼为丸，如梧桐子大，每服七八十丸，食远白汤下"},
        {"name": "枳实导滞丸", "source": "《内外伤辨惑论》", "section": "卷下", "composition": "大黄一两，枳实（麸炒）、神曲（炒）各五钱，茯苓（去皮）、黄芩（去腐）、黄连（拣净）、白术各三钱，泽泻二钱", "effects": "消导化积，清热利湿", "indications": "湿热食积证。脘腹胀痛，下痢泄泻，或大便秘结，小便短赤，舌苔黄腻，脉沉有力", "usage": "共为细末，汤浸蒸饼为丸，如梧桐子大，每服五十丸至七十丸，温水送下"},
        {"name": "健脾丸", "source": "《证治准绳》", "section": "类方", "composition": "白术二两半（炒），木香（另研）、黄连（酒炒）、甘草各七钱半，白茯苓二两，人参一两五钱，神曲（炒）、陈皮、砂仁、麦芽（炒）、山楂（取肉）、山药（炒）、肉豆蔻（面裹煨熟，纸包捶去油）各一两", "effects": "健脾和胃，消食止泻", "indications": "脾虚食积证。食少难消，脘腹痞闷，大便溏薄，倦怠乏力，苔腻微黄，脉虚弱", "usage": "共为细末，蒸饼为丸，如绿豆大，每服五十丸，空心服，一日二次，陈米汤下"},
        {"name": "乌梅丸", "source": "《伤寒论》", "section": "第338条", "composition": "乌梅三百枚，细辛六两，干姜十两，黄连十六两，当归四两，附子六两（炮，去皮），蜀椒四两（出汗），桂枝六两（去皮），人参六两，黄柏六两", "effects": "温脏安蛔", "indications": "蛔厥证。脘腹阵痛，烦闷呕吐，时发时止，得食则吐，甚则吐蛔，手足厥冷；或久泻久痢", "usage": "共为末，炼蜜为丸，如梧桐子大，先食饮服十丸，日三服"},
        {"name": "肥儿丸", "source": "《太平惠民和剂局方》", "section": "卷十", "composition": "神曲（炒）十两，黄连（去须）十两，肉豆蔻（面裹煨）、使君子（去皮）、麦芽（炒）各五两，槟榔（不见火）二十个，木香二两", "effects": "杀虫消积，健脾清热", "indications": "小儿疳积。消化不良，面黄体瘦，肚腹胀满，发热口臭，大便溏薄，以及虫积腹痛", "usage": "共为细末，猪胆为丸，如粟米大，每服三十丸，量岁数加减，热水下"},
        {"name": "十灰散", "source": "《十药神书》", "section": "卷上", "composition": "大蓟、小蓟、荷叶、侧柏叶、茅根、茜根、山栀、大黄、牡丹皮、棕榈皮各等分", "effects": "凉血止血", "indications": "血热妄行之上部出血证。呕血、吐血、咯血、嗽血、衄血等，血色鲜红，来势急暴，舌红，脉数", "usage": "各烧灰存性，研极细末，用纸包，碗盖于地上一夕，出火毒，用时先将白藕捣汁或萝卜汁磨京墨半碗，调服五钱，食后服下"},
        {"name": "咳血方", "source": "《丹溪心法》", "section": "卷二", "composition": "青黛（水飞）、瓜蒌仁（去油）、海粉（现多用海浮石）、山栀子（炒黑）、诃子各等分", "effects": "清肝宁肺，凉血止血", "indications": "肝火犯肺之咳血证。咳嗽痰稠带血，咯吐不爽，心烦易怒，胸胁作痛，咽干口苦，颊赤便秘，舌红苔黄，脉弦数", "usage": "共为末，以蜜同姜汁为丸，噙化"},
        {"name": "小蓟饮子", "source": "《重订严氏济生方》", "section": "小便门", "composition": "生地黄四两，小蓟、滑石、木通、蒲黄（炒）、藕节、淡竹叶、当归（去芦，酒浸）、山栀子（去壳）、甘草（炙）各半两", "effects": "凉血止血，利水通淋", "indications": "热结下焦之血淋、尿血。尿中带血，小便频数，赤涩热痛，舌红，脉数", "usage": "每服四钱，水一盏半，煎至八分，空心食前服"},
        {"name": "槐花散", "source": "《普济本事方》", "section": "卷五", "composition": "槐花（炒）、柏叶（杵，焙）、荆芥穗、枳壳（去瓤，细切，麸炒黄）各等分", "effects": "清肠止血，疏风行气", "indications": "风热湿毒，壅遏肠道，损伤血络证。便前出血，或便后出血，或粪中带血，以及痔疮出血，血色鲜红或晦暗，舌红苔黄脉数", "usage": "共为细末，用清米饮调下二钱，空心食前服"},
        {"name": "黄土汤", "source": "《金匮要略》", "section": "惊悸吐衄下血胸满瘀血病脉证治", "composition": "甘草、干地黄、白术、附子（炮）、阿胶、黄芩各三两，灶中黄土半斤", "effects": "温阳健脾，养血止血", "indications": "脾阳不足，脾不统血证。大便下血，先便后血，或吐血、衄血，及妇人崩漏，血色暗淡，四肢不温，面色萎黄，舌淡苔白，脉沉细无力", "usage": "水煎服"},
        {"name": "川芎茶调散", "source": "《太平惠民和剂局方》", "section": "卷二", "composition": "薄荷叶（不见火）八两，川芎、荆芥（去梗）各四两，细辛（去芦）一两，防风（去芦）一两半，白芷、羌活、甘草各二两", "effects": "疏风止痛", "indications": "外感风邪头痛。偏正头痛，或巅顶作痛，目眩鼻塞，或恶风发热，舌苔薄白，脉浮", "usage": "共为细末，每服二钱，食后，茶清调下"},
        {"name": "大定风珠", "source": "《温病条辨》", "section": "卷三", "composition": "生白芍六钱，阿胶三钱，生龟板四钱，干地黄六钱，麻仁二钱，五味子二钱，生牡蛎四钱，麦冬六钱（连心），炙甘草四钱，鸡子黄二枚（生），鳖甲四钱（生）", "effects": "滋阴熄风", "indications": "阴虚风动证。手足瘈疭，形消神倦，舌绛少苔，脉气虚弱，时时欲脱者", "usage": "水八杯，煮取三杯，去滓，再入鸡子黄，搅令相得，分三次服"},
        {"name": "杏苏散", "source": "《温病条辨》", "section": "卷一", "composition": "苏叶、半夏、茯苓、前胡、苦桔梗、枳壳、甘草、生姜、大枣（去核）、橘皮、杏仁", "effects": "轻宣凉燥，理肺化痰", "indications": "外感凉燥证。恶寒无汗，头微痛，咳嗽痰稀，鼻塞咽干，苔白脉弦", "usage": "水煎服"},
        {"name": "桑杏汤", "source": "《温病条辨》", "section": "卷一", "composition": "桑叶一钱，杏仁一钱五分，沙参二钱，象贝一钱，香豉一钱，栀皮一钱，梨皮一钱", "effects": "清宣温燥，润肺止咳", "indications": "外感温燥证。身热不甚，口渴，咽干鼻燥，干咳无痰，或痰少而粘，舌红，苔薄白而干，脉浮数而右脉大者", "usage": "水二杯，煮取一杯，顿服之，重者再作服"},
        {"name": "清燥救肺汤", "source": "《医门法律》", "section": "卷四", "composition": "桑叶（经霜者，去枝梗，净叶）三钱，石膏（煅）二钱五分，甘草一钱，人参七分，胡麻仁（炒，研）一钱，真阿胶八分，麦门冬（去心）一钱二分，杏仁（泡，去皮尖，炒黄）七分，枇杷叶一片（刷去毛，蜜涂，炙黄）", "effects": "清燥润肺，养阴益气", "indications": "温燥伤肺，气阴两伤证。身热头痛，干咳无痰，气逆而喘，咽喉干燥，鼻燥，胸满胁痛，心烦口渴，舌干少苔，脉虚大而数", "usage": "水一碗，煎六分，频频二三次滚热服"},
        {"name": "麦门冬汤", "source": "《金匮要略》", "section": "肺痿肺痈咳嗽上气病脉证治", "composition": "麦门冬七升，半夏一升，人参二两，甘草二两，粳米三合，大枣十二枚", "effects": "清养肺胃，降逆下气", "indications": "虚热肺痿。咳嗽气喘，咽喉不利，咯痰不爽，或咳唾涎沫，口干咽燥，手足心热，舌红少苔，脉虚数；或胃阴不足证", "usage": "水煎服"},
        {"name": "百合固金汤", "source": "《慎斋遗书》", "section": "卷七", "composition": "熟地、生地、归身各三钱，白芍、甘草各一钱，桔梗、玄参各八分，贝母、麦冬、百合各一钱半", "effects": "滋养肺肾，止咳化痰", "indications": "肺肾阴亏，虚火上炎证。咳嗽气喘，痰中带血，咽喉燥痛，头晕目眩，午后潮热，舌红少苔，脉细数", "usage": "水煎服"},
        {"name": "养阴清肺汤", "source": "《重楼玉钥》", "section": "卷上", "composition": "大生地二钱，麦冬一钱二分，生甘草五分，元参一钱五分，贝母八分（去心），丹皮八分，薄荷五分，炒白芍八分", "effects": "养阴清肺，解毒利咽", "indications": "白喉之阴虚燥热证。喉间起白如腐，不易拭去，咽喉肿痛，初起或发热或不发热，鼻干唇燥，或咳或不咳，呼吸有声，似喘非喘，脉数无力或细数", "usage": "水煎服"},
        {"name": "玉液汤", "source": "《医学衷中参西录》", "section": "治消渴方", "composition": "生山药一两，生黄芪五钱，知母六钱，生鸡内金二钱（捣细），葛根钱半，五味子三钱，天花粉三钱", "effects": "益气滋阴，固肾止渴", "indications": "消渴气阴两虚证。口渴引饮，小便频数量多，或小便混浊，困倦气短，舌嫩红而干，脉虚细无力", "usage": "水煎服"},
        {"name": "增液汤", "source": "《温病条辨》", "section": "卷二", "composition": "玄参一两，麦冬（连心）八钱，细生地八钱", "effects": "增液润燥", "indications": "阳明温病，津亏便秘证。大便秘结，口渴，舌干红，脉细数或沉而无力", "usage": "水八杯，煮取三杯，口干则与饮，令尽，不便，再作服"},
        {"name": "越鞠丸", "source": "《丹溪心法》", "section": "卷三", "composition": "香附、川芎、苍术、神曲、栀子各等分", "effects": "行气解郁", "indications": "六郁证。胸膈痞闷，脘腹胀痛，嗳腐吞酸，恶心呕吐，饮食不消，舌苔腻，脉弦", "usage": "共为末，水丸如绿豆大，每服二至三钱，温开水送下"},
        {"name": "枳实薤白桂枝汤", "source": "《金匮要略》", "section": "胸痹心痛短气病脉证治", "composition": "枳实四枚，厚朴四两，薤白半升，桂枝一两，瓜蒌实一枚（捣）", "effects": "通阳散结，祛痰下气", "indications": "胸痹，气结在胸证。胸满而痛，甚或胸痛彻背，喘息咳唾，短气，气从胁下冲逆，上攻心胸，舌苔白腻，脉沉弦或紧", "usage": "水煎服"},
        {"name": "半夏厚朴汤", "source": "《金匮要略》", "section": "妇人杂病脉证并治", "composition": "半夏一升，厚朴三两，茯苓四两，生姜五两，干苏叶二两", "effects": "行气散结，降逆化痰", "indications": "梅核气。咽中如有物阻，咯吐不出，吞咽不下，胸膈满闷，或咳或呕，舌苔白润或白滑，脉弦缓或弦滑", "usage": "水煎服"},
        {"name": "天台乌药散", "source": "《医学发明》", "section": "卷五", "composition": "乌药半两，木香半两，小茴香半两，青皮半两，高良姜半两（炒），槟榔二个，川楝子十个，巴豆七十粒", "effects": "行气疏肝，散寒止痛", "indications": "肝经寒凝气滞证。小肠疝气，少腹引控睾丸而痛，偏坠肿胀，或少腹疼痛，苔白，脉弦", "usage": "共为末，每服一钱，温酒送下"},
        {"name": "暖肝煎", "source": "《景岳全书》", "section": "卷五十一", "composition": "当归二三钱，枸杞三钱，茯苓二钱，小茴香二钱，肉桂一二钱，乌药二钱，沉香一钱（或木香亦可），生姜三五片", "effects": "温补肝肾，行气止痛", "indications": "肝肾不足，寒滞肝脉证。睾丸冷痛，或小腹疼痛，疝气痛，畏寒喜暖，舌淡苔白，脉沉迟", "usage": "水二盅，加生姜三五片，煎七分，食远温服"},
        {"name": "苏子降气汤", "source": "《太平惠民和剂局方》", "section": "卷三", "composition": "紫苏子、半夏各二两半，川当归一两半，甘草二两，前胡、厚朴（姜汁炒）各一两，肉桂一两半", "effects": "降气平喘，祛痰止咳", "indications": "上实下虚喘咳证。痰涎壅盛，胸膈满闷，喘咳短气，呼多吸少，或腰疼脚弱，肢体倦怠，或肢体浮肿，舌苔白滑或白腻，脉弦滑", "usage": "加生姜二片，枣子一个，苏叶五叶，水煎服"},
        {"name": "定喘汤", "source": "《摄生众妙方》", "section": "卷六", "composition": "白果二十一枚（去壳砸碎，炒黄色），麻黄三钱，苏子二钱，甘草一钱，款冬花三钱，杏仁一钱五分（去皮尖），桑白皮三钱（蜜炙），黄芩一钱五分（微炒），法制半夏三钱（如无，用甘草汤泡七次，去脐用）", "effects": "宣降肺气，清热化痰", "indications": "风寒外束，痰热内蕴证。咳喘痰多气急，质稠色黄，或微恶风寒，舌苔黄腻，脉滑数", "usage": "水三盅，煎二盅，作二服，每服一盅，不拘时，徐徐服"},
        {"name": "旋覆代赭汤", "source": "《伤寒论》", "section": "第161条", "composition": "旋覆花三两，人参二两，生姜五两，代赭石一两，甘草三两（炙），半夏半升（洗），大枣十二枚（擘）", "effects": "降逆化痰，益气和胃", "indications": "胃虚气逆痰阻证。胃脘痞闷或胀满，按之不痛，频频嗳气，或见纳差、呃逆、恶心，甚或呕吐，舌苔白腻，脉缓或滑", "usage": "水煎服"},
        {"name": "橘皮竹茹汤", "source": "《金匮要略》", "section": "呕吐哕下利病脉证治", "composition": "橘皮二斤，竹茹二升，大枣三十枚，生姜半斤，甘草五两，人参一两", "effects": "降逆止呃，益气清热", "indications": "胃虚有热之呃逆。呃逆或干呕，虚烦少气，口干，舌红嫩，脉虚数", "usage": "水煎服"},
        {"name": "桃核承气汤", "source": "《伤寒论》", "section": "第106条", "composition": "桃仁五十个（去皮尖），大黄四两，桂枝二两（去皮），甘草二两（炙），芒硝二两", "effects": "逐瘀泻热", "indications": "下焦蓄血证。少腹急结，小便自利，神志如狂，甚则烦躁谵语，至夜发热；以及血瘀经闭，痛经，脉沉实而涩", "usage": "水煎服，内芒硝"},
        {"name": "血府逐瘀汤", "source": "《医林改错》", "section": "卷上", "composition": "桃仁四钱，红花三钱，当归三钱，生地黄三钱，川芎一钱半，赤芍二钱，牛膝三钱，桔梗一钱半，柴胡一钱，枳壳二钱，甘草二钱", "effects": "活血化瘀，行气止痛", "indications": "胸中血瘀证。胸痛头痛，日久不愈，痛如针刺而有定处，或呃逆日久不止，或饮水即呛，干呕，或内热瞀闷，或心悸怔忡，失眠多梦，急躁易怒，入暮潮热，唇暗或两目暗黑，舌质暗红，或有瘀斑，脉涩或弦紧", "usage": "水煎服"},
        {"name": "补阳还五汤", "source": "《医林改错》", "section": "卷下", "composition": "黄芪四两（生），当归尾二钱，赤芍一钱半，地龙一钱（去土），川芎一钱，红花一钱，桃仁一钱", "effects": "补气，活血，通络", "indications": "气虚血瘀之中风。半身不遂，口眼㖞斜，语言謇涩，口角流涎，小便频数或遗尿失禁，舌暗淡，苔白，脉缓无力", "usage": "水煎服"},
        {"name": "复元活血汤", "source": "《医学发明》", "section": "卷三", "composition": "柴胡半两，瓜蒌根、当归各三钱，红花、甘草、穿山甲（炮）各二钱，大黄（酒浸）一两，桃仁（酒浸，去皮尖，研如泥）五十个", "effects": "活血祛瘀，疏肝通络", "indications": "跌打损伤，瘀血阻滞证。胁肋瘀肿，痛不可忍，舌红，脉弦或涩", "usage": "共为粗末，每服一两，水一盏半，酒半盏，同煎至七分，去滓，大温服之，食前"},
        {"name": "七厘散", "source": "《同寿录》", "section": "卷末", "composition": "血竭一两，麝香、冰片各一分二厘，乳香、没药、红花各一钱五分，朱砂一钱二分，儿茶二钱四分", "effects": "散瘀消肿，定痛止血", "indications": "跌打损伤，筋断骨折之瘀血肿痛，或刀伤出血；或无名肿毒，烧伤烫伤", "usage": "共为极细末，每服七厘，日服二次，或用酒调敷患处"},
        {"name": "温经汤", "source": "《金匮要略》", "section": "妇人杂病脉证并治", "composition": "吴茱萸三两，当归二两，芎藭二两，芍药二两，人参二两，桂枝二两，阿胶二两，生姜二两，牡丹皮二两（去心），甘草二两，半夏半升，麦门冬一升（去心）", "effects": "温经散寒，养血祛瘀", "indications": "冲任虚寒，瘀血阻滞证。漏下不止，月经不调，或前或后，或一月再行，或经停不至，而见傍晚发热，手心烦热，唇口干燥，少腹里急，腹满，舌暗红，脉细而涩", "usage": "水煎服，内阿胶烊消"},
        {"name": "生化汤", "source": "《傅青主女科》", "section": "卷上", "composition": "全当归八钱，川芎三钱，桃仁十四枚（去皮尖，研），干姜五分（炮黑），甘草五分（炙）", "effects": "养血祛瘀，温经止痛", "indications": "血虚寒凝，瘀血阻滞证。产后恶露不行，小腹冷痛，舌淡，苔白，脉细涩", "usage": "黄酒、童便各半煎服"},
        {"name": "失笑散", "source": "《太平惠民和剂局方》", "section": "卷九", "composition": "五灵脂（酒研，淘去沙土）、蒲黄（炒香）各等分", "effects": "活血祛瘀，散结止痛", "indications": "瘀血停滞证。心腹剧痛，或产后恶露不行，或月经不调，少腹急痛，舌暗红，脉弦或涩", "usage": "共为细末，每服二钱，用黄酒或醋冲服"},
        {"name": "桂枝茯苓丸", "source": "《金匮要略》", "section": "妇人妊娠病脉证并治", "composition": "桂枝、茯苓、牡丹（去心）、桃仁（去皮尖，熬）、芍药各等分", "effects": "活血化瘀，缓消癥块", "indications": "瘀阻胞宫证。妇人素有癥块，妊娠漏下不止，或胎动不安，血色紫黑晦暗，腹痛拒按，或经闭腹痛，或产后恶露不尽而腹痛拒按者，舌质紫暗或有瘀点，脉沉涩", "usage": "共为末，炼蜜和丸，如兔屎大，每日食前服一丸"},
        {"name": "活络效灵丹", "source": "《医学衷中参西录》", "section": "治气血瘀滞肢体疼痛方", "composition": "当归五钱，丹参五钱，生明乳香五钱，生明没药五钱", "effects": "活血祛瘀，通络止痛", "indications": "气血凝滞证。心腹疼痛，腿痛臂痛，跌打瘀肿，内外疮疡，以及癥瘕积聚", "usage": "若作散剂，一剂分作四次服，温酒送下"},
        {"name": "十枣汤", "source": "《伤寒论》", "section": "第152条", "composition": "芫花（熬）、甘遂、大戟各等分", "effects": "攻逐水饮", "indications": "悬饮。咳唾胸胁引痛，心下痞硬，干呕短气，头痛目眩，或胸背掣痛不得息，舌苔滑，脉沉弦；或水肿腹胀，二便不利，属于实证者", "usage": "三味等分，各别捣为散，以水一升半，先煮大枣肥者十枚，取八合，去滓，内药末，强人服一钱匕，羸人服半钱，平旦温服"},
        {"name": "舟车丸", "source": "《景岳全书》", "section": "卷五十五", "composition": "甘遂、芫花、大戟各一两（俱醋炒），大黄二两，黑丑（头末）四两，青皮、陈皮、木香、槟榔各半两，轻粉一钱", "effects": "行气逐水", "indications": "水热内壅，气机阻滞证。水肿水胀，口渴，气粗，腹坚，大小便秘，脉沉数有力", "usage": "共为末，水糊为丸，如小豆大，空心温水下，初服五丸，日三服"},
        {"name": "大黄附子汤", "source": "《金匮要略》", "section": "腹满寒疝宿食病脉证治", "composition": "大黄三两，附子三枚（炮），细辛二两", "effects": "温里散寒，通便止痛", "indications": "寒积里实证。腹痛便秘，胁下偏痛，发热，手足厥冷，舌苔白腻，脉弦紧", "usage": "水煎服，大黄后下"},
        {"name": "麻子仁丸", "source": "《伤寒论》", "section": "第247条", "composition": "麻子仁二升，芍药半斤，枳实半斤（炙），大黄一斤（去皮），厚朴一尺（炙，去皮），杏仁一升（去皮尖，熬，别作脂）", "effects": "润肠泄热，行气通便", "indications": "脾约证。肠胃燥热，脾津不足，大便干结，小便频数，舌苔微黄，脉细涩", "usage": "共为细末，炼蜜为丸，如梧桐子大，饮服十丸，日三服"},
        {"name": "济川煎", "source": "《景岳全书》", "section": "卷五十一", "composition": "当归三至五钱，牛膝二钱，肉苁蓉二至三钱（酒洗去咸），泽泻一钱半，升麻五分至七分或一钱，枳壳一钱（虚甚者不必用）", "effects": "温肾益精，润肠通便", "indications": "肾阳虚弱，精津不足证。大便秘结，小便清长，腰膝酸软，头目眩晕，舌淡苔白，脉沉迟", "usage": "水一盅半，煎七分，食前服"},
        {"name": "黄龙汤", "source": "《伤寒六书》", "section": "卷三", "composition": "大黄、芒硝、枳实、厚朴、甘草、人参、当归", "effects": "攻下热结，益气养血", "indications": "阳明腑实，气血不足证。自利清水，色纯青，或大便秘结，脘腹胀满，腹痛拒按，身热口渴，神疲少气，谵语，甚则循衣摸床，撮空理线，神昏肢厥，舌苔焦黄或焦黑，脉虚", "usage": "加生姜三片，大枣二枚，水煎服"},
        {"name": "新加黄龙汤", "source": "《温病条辨》", "section": "卷二", "composition": "细生地五钱，麦冬五钱，玄参五钱，生大黄三钱，芒硝一钱，生甘草二钱，人参一钱半（另煎），当归一钱半，海参二条（洗），姜汁六匙", "effects": "泄热通便，滋阴益气", "indications": "热结里实，气阴不足证。大便秘结，腹中胀满而硬，神倦少气，口干咽燥，唇裂舌焦，苔焦黄或焦黑燥裂，脉沉细", "usage": "水煎服"},
        {"name": "增液承气汤", "source": "《温病条辨》", "section": "卷二", "composition": "玄参一两，麦冬（连心）八钱，细生地八钱，大黄三钱，芒硝一钱五分", "effects": "滋阴增液，泄热通便", "indications": "阳明温病，热结阴亏证。燥屎不行，下之不通，脘腹胀满，口干唇燥，舌红苔黄，脉细数", "usage": "水八杯，煮取三杯，先服一杯，不知，再服"},
        {"name": "小柴胡汤", "source": "《伤寒论》", "section": "第96条", "composition": "柴胡半斤，黄芩三两，人参三两，半夏半升（洗），甘草三两（炙），生姜三两（切），大枣十二枚（擘）", "effects": "和解少阳", "indications": "伤寒少阳证。往来寒热，胸胁苦满，默默不欲饮食，心烦喜呕，口苦，咽干，目眩，舌苔薄白，脉弦", "usage": "水煎服"},
        {"name": "大柴胡汤", "source": "《金匮要略》", "section": "腹满寒疝宿食病脉证治", "composition": "柴胡半斤，黄芩三两，芍药三两，半夏半升（洗），生姜五两（切），枳实四枚（炙），大枣十二枚（擘），大黄二两", "effects": "和解少阳，内泻热结", "indications": "少阳阳明合病。往来寒热，胸胁苦满，呕不止，郁郁微烦，心下痞硬，或心下满痛，大便不解，或协热下利，舌苔黄，脉弦数有力", "usage": "水煎服"},
        {"name": "蒿芩清胆汤", "source": "《重订通俗伤寒论》", "section": "卷二", "composition": "青蒿脑一钱半至二钱，淡竹茹三钱，仙半夏一钱半，赤茯苓三钱，青子芩一钱半至三钱，生枳壳一钱半，陈广皮一钱半，碧玉散（包）三钱", "effects": "清胆利湿，和胃化痰", "indications": "少阳湿热痰浊证。寒热如疟，寒轻热重，口苦膈闷，吐酸苦水，或呕黄涎而粘，甚则干呕呃逆，胸胁胀疼，小便黄少，舌红苔白腻，间现杂色，脉数而右滑左弦", "usage": "水煎服"},
        {"name": "达原饮", "source": "《温疫论》", "section": "卷上", "composition": "槟榔二钱，厚朴一钱，草果仁五分，知母一钱，芍药一钱，黄芩一钱，甘草五分", "effects": "开达膜原，辟秽化浊", "indications": "瘟疫或疟疾，邪伏膜原证。憎寒壮热，或一日三次，或一日一次，发无定时，胸闷呕恶，头痛烦躁，脉弦数，舌边深红，舌苔垢腻，或苔白厚如积粉", "usage": "水煎服"},
        {"name": "四逆散", "source": "《伤寒论》", "section": "第318条", "composition": "甘草（炙）、枳实（破，水渍，炙干）、柴胡、芍药各十分", "effects": "透邪解郁，疏肝理脾", "indications": "阳郁厥逆证。手足不温，或腹痛，或泄利下重，脉弦；或肝脾气郁证，胁肋胀闷，脘腹疼痛，脉弦", "usage": "共为细末，白饮和服方寸匕，日三服"},
        {"name": "逍遥散", "source": "《太平惠民和剂局方》", "section": "卷九", "composition": "甘草（炙）半两，当归（去苗，锉，微炒）、茯苓（去皮，白者）、芍药（白）、白术、柴胡（去苗）各一两", "effects": "疏肝解郁，养血健脾", "indications": "肝郁血虚脾弱证。两胁作痛，头痛目眩，口燥咽干，神疲食少，或往来寒热，或月经不调，乳房胀痛，脉弦而虚", "usage": "共为粗末，每服二钱，水一大盏，烧生姜一块切破，薄荷少许，同煎至七分，去渣热服，不拘时候"},
        {"name": "痛泻要方", "source": "《丹溪心法》", "section": "卷二", "composition": "炒白术三两，炒白芍二两，炒陈皮一两半，防风一两", "effects": "补脾柔肝，祛湿止泻", "indications": "脾虚肝旺之痛泻。肠鸣腹痛，大便泄泻，泻必腹痛，泻后痛缓，舌苔薄白，脉两关不调，左弦而右缓者", "usage": "水煎服，或作散剂，每服二钱，米饮调下"},
        {"name": "半夏泻心汤", "source": "《伤寒论》", "section": "第149条", "composition": "半夏半升（洗），黄芩、干姜、人参、甘草（炙）各三两，黄连一两，大枣十二枚（擘）", "effects": "寒热平调，消痞散结", "indications": "寒热错杂之痞证。心下痞，但满而不痛，或呕吐，肠鸣下利，舌苔腻而微黄", "usage": "水煎服"},
        {"name": "生姜泻心汤", "source": "《伤寒论》", "section": "第157条", "composition": "生姜四两（切），甘草三两（炙），人参三两，干姜一两，黄芩三两，半夏半升（洗），黄连一两，大枣十二枚（擘）", "effects": "和胃消痞，宣散水气", "indications": "水热互结于中焦，脾胃升降失常之痞证。心下痞硬，干噫食臭，腹中雷鸣下利，舌苔白腻或黄腻，脉滑或弦", "usage": "水煎服"},
        {"name": "甘草泻心汤", "source": "《伤寒论》", "section": "第158条", "composition": "甘草四两（炙），黄芩三两，干姜三两，半夏半升（洗），大枣十二枚（擘），黄连一两", "effects": "和胃补中，降逆消痞", "indications": "胃气虚弱，气结成痞证。下利日数十行，谷不化，腹中雷鸣，心下痞硬而满，干呕心烦不得安，舌淡苔白腻，脉濡或缓", "usage": "水煎服"},
        {"name": "黄连汤", "source": "《伤寒论》", "section": "第173条", "composition": "黄连三两，甘草三两（炙），干姜三两，桂枝三两（去皮），人参二两，半夏半升（洗），大枣十二枚（擘）", "effects": "平调寒热，和胃降逆", "indications": "上热下寒证。胸中有热，胃中有邪气，腹中痛，欲呕吐，舌淡苔白，脉弦或缓", "usage": "水煎服"},
        {"name": "白虎加人参汤", "source": "《伤寒论》", "section": "第26条", "composition": "知母六两，石膏一斤（碎，绵裹），甘草（炙）二两，粳米六合，人参三两", "effects": "清热，益气，生津", "indications": "气分热盛，气阴两伤证。高热，大汗出，口燥渴，心烦，背微恶寒，舌干红，脉洪大无力或芤", "usage": "米熟汤成，温服"},
        {"name": "竹叶石膏汤", "source": "《伤寒论》", "section": "第397条", "composition": "竹叶二把，石膏一斤，半夏半升（洗），麦门冬一升（去心），人参二两，甘草二两（炙），粳米半升", "effects": "清热生津，益气和胃", "indications": "伤寒、温病、暑病余热未清，气津两伤证。身热多汗，心胸烦闷，气逆欲呕，口干喜饮，或虚烦不寐，舌红少苔，脉虚数", "usage": "水煎服，米熟汤成"},
        {"name": "清营汤", "source": "《温病条辨》", "section": "卷一", "composition": "犀角三钱，生地黄五钱，元参三钱，竹叶心一钱，麦冬三钱，丹参二钱，黄连一钱五分，银花三钱，连翘二钱（连心用）", "effects": "清营解毒，透热养阴", "indications": "热入营分证。身热夜甚，神烦少寐，时有谵语，目常喜开或喜闭，口渴或不渴，斑疹隐隐，舌绛而干，脉数或细数", "usage": "水煎服"},
        {"name": "清宫汤", "source": "《温病条辨》", "section": "卷一", "composition": "元参心三钱，莲子心五分，竹叶卷心二钱，连翘心二钱，犀角尖二钱（磨冲），连心麦冬三钱", "effects": "清心解毒，养阴生津", "indications": "温病液伤，邪陷心包证。发热，神昏谵语，舌绛，脉细数", "usage": "水煎服"},
        {"name": "犀角地黄汤", "source": "《备急千金要方》", "section": "卷十二", "composition": "犀角一两，生地黄八两，芍药三两，牡丹皮二两", "effects": "清热解毒，凉血散瘀", "indications": "热入血分证。热扰心神，身热谵语，斑色紫黑，舌绛起刺，脉细数；或喜忘如狂；或吐血、衄血、便血、尿血等", "usage": "水煎服"},
