        {"name": "养老", "meridian": "手太阳小肠经", "location": "在前臂背面尺侧，当尺骨小头近端桡侧凹陷中", "indications": "目视不明，肩、背、肘、臂酸痛，急性腰痛", "manipulation": "直刺或斜刺0.5-0.8寸", "source": "《针灸甲乙经》"},
        {"name": "听宫", "meridian": "手太阳小肠经", "location": "在面部，耳屏前，下颌骨髁状突的后方，张口时呈凹陷处", "indications": "耳鸣，耳聋，聤耳，齿痛，癫狂痫", "manipulation": "张口，直刺1-1.5寸", "source": "《针灸甲乙经》"},
        {"name": "睛明", "meridian": "足太阳膀胱经", "location": "在面部，目内眦角稍上方凹陷处", "indications": "目赤肿痛，流泪，视物不明，目眩，近视，夜盲，色盲", "manipulation": "嘱患者闭目，医者左手轻推眼球向外侧固定，右手缓慢进针，紧靠眶缘直刺0.5-1寸", "source": "《针灸甲乙经》"},
