        {"name": "至阴", "meridian": "足太阳膀胱经", "location": "在足小趾末节外侧，距趾甲角0.1寸", "indications": "头痛，目痛，鼻塞，鼻衄，胎位不正，难产", "manipulation": "浅刺0.1寸", "source": "《针灸甲乙经》"},
        {"name": "涌泉", "meridian": "足少阴肾经", "location": "在足底部，卷足时足前部凹陷处，约当第2、3趾趾缝纹头端与足跟连线的前1/3与后2/3交点上", "indications": "头痛，头晕，小便不利，便秘，小儿惊风，足心热，癫疾，霍乱转筋，昏厥", "manipulation": "直刺0.5-1寸", "source": "《针灸甲乙经》"},
