        {"name": "复溜", "meridian": "足少阴肾经", "location": "在小腿内侧，太溪直上2寸，跟腱的前方", "indications": "泄泻，肠鸣，水肿，腹胀，腿肿，足痿，盗汗，脉微细时无，身热无汗，腰脊强痛", "manipulation": "直刺0.5-1寸", "source": "《针灸甲乙经》"},
        {"name": "阴谷", "meridian": "足少阴肾经", "location": "在腘窝内侧，屈膝时，当半腱肌肌腱与半膜肌肌腱之间", "indications": "阳痿，疝痛，月经不调，崩漏，小便难，阴中痛，癫狂，膝股内侧痛", "manipulation": "直刺0.8-1.2寸", "source": "《针灸甲乙经》"},
